void bip388_binding_range(bip388_binding_kind_t k, uint32_t *lo, uint32_t *hi) {
    switch (k) {
        case BK_BLOCKS: *lo = 1; *hi = 65536u; return;
        case BK_RELATIVE_TIME: *lo = 4194305u; *hi = 4259840u; return;
        case BK_BLOCK_HEIGHT: *lo = 1; *hi = 500000000u; return;
        case BK_TIMESTAMP: *lo = 500000000u; *hi = 0; return;
        default: *lo = 0; *hi = 0; return;
    }
}

